{action_set_definitions}: {
  "get_batch_metadata": {
    "description": "Retrieves the initial details of a batch, including processing facility, timestamp, and the total expected yield/quantity.",
    "parameters": {
      "type": "object",
      "properties": {
        "batch_id": {
          "type": "string",
          "description": "The unique ID of the batch (e.g., 'BCH-TOM-101')."
        }
      },
      "required": [
        "batch_id"
      ]
    },
    "example_output": {
      "facility_id": "FAC-PROC-05",
      "production_time": "2023-10-27T10:00:00Z",
      "total_yield_quantity": 750
    }
  },
  "inspect_facility_sanitation": {
    "description": "Queries processing logs for a specific facility to determine if sanitation standards were met and identifies the required 'Bracketing' time window if a failure is found.",
    "parameters": {
      "type": "object",
      "properties": {
        "facility_id": {
          "type": "string",
          "description": "The ID of the processing facility."
        },
        "target_timestamp": {
          "type": "string",
          "description": "The timestamp of the contaminated batch to center the search."
        }
      },
      "required": [
        "facility_id",
        "target_timestamp"
      ]
    },
    "example_output": {
      "sanitation_failure_detected": true,
      "bracketing_start": "2023-10-27T06:00:00Z",
      "bracketing_end": "2023-10-27T14:00:00Z"
    }
  },
  "trace_product_lineage": {
    "description": "Maps ingredient batches to downstream derived products and the specific facilities (e.g., FC-NORTH-01) where they were processed or stored.",
    "parameters": {
      "type": "object",
      "properties": {
        "source_batch_ids": {
          "type": "array",
          "items": {
            "type": "string"
          },
          "description": "List of source/ingredient batch IDs."
        }
      },
      "required": [
        "source_batch_ids"
      ]
    },
    "example_output": {
      "derived_items": [
        {
          "product_id": "PROD-SALAD-XYZ",
          "derived_batch_id": "BCH-SAL-999",
          "current_facility": "FC-NORTH-01"
        }
      ]
    }
  },
  "get_unit_distribution_details": {
    "description": "Retrieves real-time logistics data for all units associated with specific batches, including current location, delivery status, and quantity per shipment.",
    "parameters": {
      "type": "object",
      "properties": {
        "batch_ids": {
          "type": "array",
          "items": {
            "type": "string"
          },
          "description": "The IDs of batches to track."
        }
      },
      "required": [
        "batch_ids"
      ]
    },
    "example_output": {
      "total_tracked_quantity": 750,
      "units": [
        {
          "unit_id": "UNIT-001",
          "location": "In-Transit",
          "delivery_status": "Out-for-Delivery",
          "quantity": 1
        }
      ]
    }
  },
  "execute_safety_intervention": {
    "description": "Executes a safety action on a unit and sets its terminal status. For 'Ghost Delivery' risks (Out-for-Delivery or Delivered), Omnichannel notifications must be used.",
    "parameters": {
      "type": "object",
      "properties": {
        "unit_id": {
          "type": "string",
          "description": "The ID of the unit."
        },
        "intervention_type": {
          "type": "string",
          "enum": [
            "Carrier_Intercept",
            "Omnichannel_Notification",
            "Physical_Destruction"
          ],
          "description": "The method used to secure the unit."
        },
        "terminal_status": {
          "type": "string",
          "enum": [
            "FC_Destroyed",
            "Carrier_Intercepted",
            "Consumer_DIF"
          ],
          "description": "The final safety disposition."
        }
      },
      "required": [
        "unit_id",
        "intervention_type",
        "terminal_status"
      ]
    },
    "example_output": {
      "success": true,
      "new_status": "Consumer_DIF"
    }
  },
  "check_reconciliation_compliance": {
    "description": "Aggregates terminal status data to verify if the total reconciled quantity matches the target yield.",
    "parameters": {
      "type": "object",
      "properties": {
        "target_quantity": {
          "type": "number",
          "description": "The total units expected to be reconciled (e.g., 750)."
        },
        "implicated_batch_ids": {
          "type": "array",
          "items": {
            "type": "string"
          },
          "description": "Batches to check against."
        }
      },
      "required": [
        "target_quantity",
        "implicated_batch_ids"
      ]
    },
    "example_output": {
      "reconciled_count": 750,
      "compliance_percentage": 100.0,
      "reconciliation_complete": true
    }
  }
}
